# WRONG: treat all responses the same
for response in responses:
    if response["status"] == "ok":
        process(response)
    # edge cases silently discarded

# RIGHT: count and log edge case types
from collections import Counter
edge_counts = Counter()
for response in responses:
    if response["status"] != "ok":
        edge_counts[response["status"]] += 1
        log_edge_case(response)
    else:
        process(response)

# Alert if any edge case type exceeds threshold
for status, count in edge_counts.items():
    rate = count / len(responses)
    if rate > 0.05:
        alert(f"Edge case rate for {status} is {rate:.1%} — exceeds 5% threshold")
